import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, ShoppingCart, User, Menu, X, Heart, Store } from 'lucide-react';
import MegaMenu from './megamenu';
import { useCart } from '../../hooks/usecart';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState(null);
  const { user, isAuthenticated } = useSelector((state) => state.auth);
  const { getItemCount } = useCart();
  const navigate = useNavigate();

  // Updated top page menu to include product counts
  const categories = [
    {
      name: 'Living Room',
      slug: 'living-room',
      subcategories: [
        { name: 'Sofas', slug: 'sofas', count: 142 },
        { name: 'TV Units', slug: 'tv-units', count: 56 },
        { name: 'Coffee Tables', slug: 'coffee-tables', count: 89 },
        { name: 'Bookshelves', slug: 'bookshelves', count: 34 },
        { name: 'Shoe Racks', slug: 'shoe-racks', count: 21 },
      ],
    },
    {
      name: 'Bedroom',
      slug: 'bedroom',
      subcategories: [
        { name: 'Beds', slug: 'beds', count: 110 },
        { name: 'Wardrobes', slug: 'wardrobes', count: 75 },
        { name: 'Dressers', slug: 'dressers', count: 42 },
        { name: 'Nightstands', slug: 'nightstands', count: 88 },
        { name: 'Mattresses', slug: 'mattresses', count: 60 },
      ],
    },
    {
      name: 'Dining',
      slug: 'dining',
      subcategories: [
        { name: 'Dining Sets', slug: 'dining-sets', count: 45 },
        { name: 'Dining Tables', slug: 'dining-tables', count: 30 },
        { name: 'Chairs', slug: 'chairs', count: 150 },
        { name: 'Cabinets', slug: 'cabinets', count: 28 },
        { name: 'Bar Furniture', slug: 'bar-furniture', count: 15 },
      ],
    },
    {
      name: 'Study',
      slug: 'study',
      subcategories: [
        { name: 'Study Tables', slug: 'study-tables', count: 65 },
        { name: 'Office Chairs', slug: 'office-chairs', count: 90 },
        { name: 'Bookshelves', slug: 'bookshelves', count: 34 },
        { name: 'Laptop Tables', slug: 'laptop-tables', count: 22 },
      ],
    },
  ];

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setIsSearchOpen(false);
    }
  };

  return (
    <>
      <header className="sticky top-0 z-50 bg-white shadow-sm">
        {/* Top Bar */}
        <div className="bg-primary-50 text-gray-800 border-b border-gray-200 text-xs py-2 px-4 text-center hidden md:block">
          <span className="font-medium">
            Free Shipping on Orders Above ₹10,000 | <span className="text-brand-orange font-bold">Use Code: VIDEM10</span>
          </span>
        </div>

        {/* Main Navbar */}
        <div className="container mx-auto px-4 py-3 md:py-4">
          <div className="flex items-center justify-between gap-4 md:gap-8">
            <div className="flex items-center">
              {/* Mobile Menu Button */}
              <button
                className="md:hidden p-2 -ml-2 mr-2 text-gray-700"
                onClick={() => setIsMenuOpen(!isMenuOpen)}
              >
                {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
              </button>

              {/* Logo */}
              <Link to="/" className="flex-shrink-0">
                <h1 className="text-2xl md:text-3xl font-black text-gray-900 tracking-tight">
                  Videm's <span className="text-brand-orange">Gallery</span>
                </h1>
              </Link>
            </div>

            {/* Desktop Search Bar */}
            <div className="hidden md:flex flex-1 max-w-2xl relative">
              <form onSubmit={handleSearch} className="w-full relative">
                <input
                  type="text"
                  placeholder="Search for furniture and more..."
                  className="w-full pl-4 pr-12 py-3 bg-gray-100 rounded-md text-sm focus:bg-white border border-transparent focus:border-brand-orange transition shadow-sm"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                <button type="submit" className="absolute right-0 top-0 bottom-0 px-5 bg-brand-orange text-white rounded-r-md hover:bg-orange-600 transition flex items-center justify-center">
                  <Search className="w-5 h-5" />
                </button>
              </form>
            </div>

            {/* Right Actions */}
            <div className="flex items-center space-x-4 md:space-x-6">
              <button
                className="p-2 md:hidden text-gray-700"
                onClick={() => setIsSearchOpen(!isSearchOpen)}
              >
                <Search className="w-6 h-6" />
              </button>

              {/* SHOP NOW BUTTON */}
              <Link
                to="/products"
                className="hidden lg:flex items-center gap-2 bg-brand-orange text-white px-4 py-2 rounded-md font-semibold hover:bg-orange-600 transition shadow-sm"
              >
                <Store className="w-4 h-4" />
                <span>Shop Now</span>
              </Link>

              <Link
                to={isAuthenticated ? '/account' : '/login'}
                className="hidden md:flex flex-col items-center text-gray-700 hover:text-brand-orange transition"
              >
                <User className="w-6 h-6 mb-1" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Profile</span>
              </Link>

              <Link
                to="/wishlist"
                className="hidden md:flex flex-col items-center text-gray-700 hover:text-brand-orange transition"
              >
                <Heart className="w-6 h-6 mb-1" />
                <span className="text-[10px] font-bold uppercase tracking-wider">Wishlist</span>
              </Link>

              <Link to="/cart" className="flex flex-col items-center text-gray-700 hover:text-brand-orange transition relative">
                <div className="relative">
                  <ShoppingCart className="w-6 h-6 md:mb-1" />
                  {getItemCount() > 0 && (
                    <span className="absolute -top-2 -right-2 bg-brand-orange text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center shadow-sm">
                      {getItemCount()}
                    </span>
                  )}
                </div>
                <span onClick={() => { }} className="hidden md:block text-[10px] font-bold uppercase tracking-wider">Cart</span>
              </Link>
            </div>
          </div>
        </div>

        {/* Secondary Navigation */}
        <div className="hidden md:block border-t border-b border-gray-200 bg-white">
          <div className="container mx-auto px-4">
            <nav className="flex items-center justify-center space-x-8">
              {categories.map((cat) => (
                <div
                  key={cat.slug}
                  className="relative group"
                  onMouseEnter={() => setActiveCategory(cat)}
                  onMouseLeave={() => setActiveCategory(null)}
                >
                  <Link
                    to={`/category/${cat.slug}`}
                    className="block text-sm font-bold text-gray-800 hover:text-brand-orange py-3 uppercase tracking-wide transition"
                  >
                    {cat.name}
                  </Link>
                </div>
              ))}
            </nav>
          </div>
        </div>

        {/* Mobile Search Bar */}
        {isSearchOpen && (
          <div className="md:hidden px-4 pb-3 border-t border-gray-100 pt-2">
            <form onSubmit={handleSearch} className="relative">
              <input
                type="text"
                placeholder="Search furniture..."
                className="w-full pl-10 pr-4 py-2.5 bg-gray-100 rounded-lg text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                autoFocus
              />
              <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
            </form>
          </div>
        )}

        {/* Mega Menu (Make sure to update MegaMenu component to accept the new count properties) */}
        {activeCategory && (
          <MegaMenu
            category={activeCategory}
            onClose={() => setActiveCategory(null)}
          />
        )}
      </header>

      {/* Mobile Menu Overlay */}
      {isMenuOpen && (
        <div className="fixed inset-0 z-40 bg-white md:hidden">
          <div className="pt-16 px-4 pb-20 h-full overflow-y-auto">

            {/* Mobile Shop Now Button */}
            <div className="mb-6">
              <Link
                to="/products"
                onClick={() => setIsMenuOpen(false)}
                className="w-full flex items-center justify-center gap-2 bg-brand-orange text-white px-4 py-3 rounded-lg font-semibold shadow-sm"
              >
                <Store className="w-5 h-5" />
                Shop All Products
              </Link>
            </div>

            <div className="space-y-1">
              {categories.map((cat) => (
                <div key={cat.slug} className="border-b border-gray-100">
                  <Link
                    to={`/category/${cat.slug}`}
                    className="block py-3 text-base font-medium text-gray-900"
                    onClick={() => setIsMenuOpen(false)}
                  >
                    {cat.name}
                  </Link>
                  <div className="pl-4 pb-2 space-y-2">
                    {/* Render the subcategory and its product count */}
                    {cat.subcategories.map((sub) => (
                      <Link
                        key={sub.slug}
                        to={`/category/${cat.slug}/${sub.slug}`}
                        className="flex items-center justify-between py-1.5 text-sm text-gray-600 hover:text-brand-orange"
                        onClick={() => setIsMenuOpen(false)}
                      >
                        <span>{sub.name}</span>
                        <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">
                          {sub.count}
                        </span>
                      </Link>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-6 pt-6 border-t border-gray-200">
              {!isAuthenticated ? (
                <Link
                  to="/login"
                  className="flex items-center py-3 text-base font-medium text-gray-900"
                  onClick={() => setIsMenuOpen(false)}
                >
                  <User className="w-5 h-5 mr-3" />
                  Login / Register
                </Link>
              ) : (
                <div className="space-y-3">
                  <p className="font-medium text-gray-900">
                    Hello, {user?.first_name || 'User'}
                  </p>
                  <Link to="/account/orders" className="block text-sm text-gray-600">
                    My Orders
                  </Link>
                  <Link to="/account/addresses" className="block text-sm text-gray-600">
                    Addresses
                  </Link>
                  <button className="text-sm text-red-600">Logout</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Navbar;
